  if (value.trim().length < 1) {
    errors.push('name must be at least 1 character');
  } else if (value.length > 100) {
    errors.push('name must be at most 100 characters');
  }

  return errors;
}

/**
 * Validate a user `email` field.
 * @param {*} value  - raw value from request body
 * @returns {string[]} array of validation error messages
 */
function validateEmail(value) {
  const errors = [];

  if (value === undefined || value === null) {
    errors.push('email is required');
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push('email must be a string');
    return errors;
  }

  if (value.length > 254) {
    errors.push('email must be at most 254 characters');
  }

  if (!EMAIL_REGEX.test(value)) {
    errors.push('email must be a valid email address');
  }

  return errors;
}

/**
 * Validate the fields required to create a user (POST /users).
 * @param {object} body - req.body
 * @returns {string[]} aggregated validation errors
 */
function validateCreateUser(body) {
  return [
    ...validateName(body.name),
    ...validateEmail(body.email),
  ];
}

/**
 * Validate the fields required to update a user (PUT /users/:id).
 * At least one of name / email must be provided; present fields are validated.
 * @param {object} params - req.params
 * @param {object} body   - req.body
 * @returns {string[]} aggregated validation errors
 */
function validateUpdateUser(params, body) {
  const errors = [...validateId(params.id)];

  const hasName  = body.name  !== undefined && body.name  !== null;
  const hasEmail = body.email !== undefined && body.email !== null;

  if (!hasName && !hasEmail) {
    errors.push('at least one of name or email must be provided');
    return errors;
  }

  if (hasName)  errors.push(...validateName(body.name));
  if (hasEmail) errors.push(...validateEmail(body.email));

  return errors;
}

/**
 * Express middleware factory — runs `validatorFn` and short-circuits with a
 * 400 response listing all failures when any are found.
 *
 * Usage:
 *   router.post('/users', validate(validateCreateUser, (req) => [req.body]), handler)
 *
 * @param {Function} validatorFn  - function(...args) => string[]
 * @param {Function} argExtractor - function(req) => array of args to pass to validatorFn
 */
function validate(validatorFn, argExtractor) {
  return (req, res, next) => {
    const args   = argExtractor(req);
    const errors = validatorFn(...args);

    if (errors.length > 0) {
      return res.status(400).json({ errors });
    }

    next();
  };
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateCreateUser,
  validateUpdateUser,
  validate,
};

