// Validation helper module
// Keeps route handlers clean by centralising all field-level checks.

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const NAME_MIN = 1;
const NAME_MAX = 100;
const EMAIL_MAX = 254;

/**
 * Validate a numeric id value (param or query string arrives as a string).
 * Returns an error message, or null when valid.
 */
function validateId(value) {
  const num = Number(value);
  if (value === undefined || value === null || value === '') {
    return 'id is required';
  }
  if (!Number.isFinite(num) || !Number.isInteger(num) || num <= 0) {
    return 'id must be a positive integer';
  }
  return null;
}

/**
 * Validate a name field.
 * Returns an error message, or null when valid.
 */
function validateName(value) {
  if (typeof value !== 'string') {
    return 'name must be a string';
  }
  const trimmed = value.trim();
  if (trimmed.length < NAME_MIN) {
    return `name must be at least ${NAME_MIN} character`;
  }
  if (trimmed.length > NAME_MAX) {
    return `name must be at most ${NAME_MAX} characters`;
  }
  return null;
}

/**
 * Validate an email field.
 * Returns an error message, or null when valid.
 */
function validateEmail(value) {
  if (typeof value !== 'string') {
    return 'email must be a string';
  }
  if (value.length > EMAIL_MAX) {
    return `email must be at most ${EMAIL_MAX} characters`;
  }
  if (!EMAIL_REGEX.test(value)) {
    return 'email must be a valid email address';
  }
  return null;
}

/**
 * Check that every field name in `fields` exists (non-undefined, non-null,
 * non-empty-string) inside `body`.
 * Returns an array of error messages (empty when all fields are present).
 */
function validateRequiredFields(body, fields) {
  const errors = [];
  for (const field of fields) {
    const value = body[field];
    if (value === undefined || value === null || value === '') {
      errors.push(`${field} is required`);
    }
  }
  return errors;
}

/**
 * Run an array of field validators and collect every non-null error.
 *
 * `checks` is an array of [value, validatorFn] pairs, e.g.:
 *   [ [req.body.name, validateName], [req.body.email, validateEmail] ]
 *
 * Returns an array of error strings (empty when all pass).
 */
function runValidators(checks) {
  const errors = [];
  for (const [value, fn] of checks) {
    const error = fn(value);
    if (error !== null) {
      errors.push(error);
    }
  }
  return errors;
}

/**
 * Send a 400 response with a structured errors array.
 * Convenience wrapper so route handlers stay a single line.
 */
function sendValidationError(res, errors) {
  return res.status(400).json({ errors });
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateRequiredFields,
  runValidators,
  sendValidationError,
};

